declare @jobName nvarchar(4000)
if exists(select 1 from dmvv where ma_vv = @ma_vv)
  select @jobName = rtrim(isnull(case when @@language = 'V' then ten_vv else ten_vv2 end, '')) from dmvv where ma_vv = @ma_vv
else
  select @jobName = ''
select 'this._jobName = ''' + replace(replace(@jobName, '\', '\\'), '''', '\''') + '''; this._queryFilterString = ''' + replace(replace(@@queryString, '\', '\\'), '''', '\''') + '''; init$GridQuery$(this);' as message
return




    &XMLWhenReportLoading;
    &XMLWhenReportClosing;




      &DeclareCommandFilter;



        &QueryString;

declare @queryWhereClause nvarchar(4000), @specialWhereClause nvarchar(4000), @queryFormClause nvarchar(4000)
select @queryFormClause = 'left join dmkh b on a.ma_kh = b.ma_kh'
select @queryWhereClause = 'a.ma_vv = ''' +  replace(@ma_vv, '''', '''''') + ''''

if @so_ct1 <> '' select @queryWhereClause = @queryWhereClause + ' and a.so_ct >= ''' + dbo.ff_PadL(replace(rtrim(@so_ct1), '''', ''''''), @maxLength) + ''''
if @so_ct2 <> '' select @queryWhereClause = @queryWhereClause + ' and a.so_ct <= ''' + dbo.ff_PadL(replace(rtrim(@so_ct2), '''', ''''''), @maxLength) + ''''

if @tk_gt <> '' select @specialWhereClause = '((1 = 1 @tk @tk_du @ps1) or (1 = 1 @tk @tk_du @tk_gt @ps2))'
  else select @specialWhereClause = '(1 = 1 @tk @tk_du @ps1)'
if @tk_du <> '' select @specialWhereClause = replace(@specialWhereClause, '@tk_du', 'and ' + dbo.FastBusiness$Function$System$GetAccountFilter('a.tk_du', 'inlist', @tk_du))
  else select @specialWhereClause = replace(@specialWhereClause, '@tk_du', '')
if @tk_gt <> '' select @specialWhereClause = replace(@specialWhereClause, '@tk_gt', 'and ' + dbo.FastBusiness$Function$System$GetAccountFilter('a.tk_du', 'notinlist', @tk_gt))
  else select @specialWhereClause = replace(@specialWhereClause, '@tk_gt', '')
if @tk <> '' select @specialWhereClause = replace(@specialWhereClause, '@tk', 'and ' + dbo.FastBusiness$Function$System$GetAccountFilter('a.tk', 'inlist', @tk))
  else select @specialWhereClause = replace(@specialWhereClause, '@tk', '')
if @ghi_no_co = '1' begin
  select @specialWhereClause = replace(@specialWhereClause, '@ps1', 'and a.ps_no + a.ps_no_nt <> 0')
  select @specialWhereClause = replace(@specialWhereClause, '@ps2', 'and a.ps_co + a.ps_co_nt <> 0')
end
if @ghi_no_co = '2' begin
  select @specialWhereClause = replace(@specialWhereClause, '@ps1', 'and a.ps_co + a.ps_co_nt <> 0')
  select @specialWhereClause = replace(@specialWhereClause, '@ps2', 'and a.ps_no + a.ps_no_nt <> 0')
end
select @specialWhereClause = replace(replace(@specialWhereClause, '@ps1', ''), '@ps2', '')
select @queryWhereClause = @queryWhereClause + ' and ' + @specialWhereClause

if @vv_me <> '' select @queryWhereClause = @queryWhereClause + ' and (dbo.ff_IsRelationJob(''' + replace(rtrim(@vv_me), '''', '''''') + ''', a.ma_vv) = 1)'
if @ma_kh <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_kh like ''' + replace(rtrim(@ma_kh), '''', '''''') + '%'''
if @ma_ct <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_ct like ''' + replace(rtrim(@ma_ct), '''', '''''') + '%'''
if @ma_nt <> '' select @queryWhereClause = @queryWhereClause + ' and a.ma_nt like ''' + replace(rtrim(@ma_nt), '''', '''''') + '%'''

&FilterInitialize;&FilterQuery;
exec FastBusiness$Report$GLDetail @@refresh, @@pageIndex, @@pageCount, @@lastPage, @@lastCount, @@firstItem, @@lastItem,
  @@textExternal, @queryFormClause, @queryWhereClause, @ngay_ct1, @ngay_ct2, @ma_dvcs, @@admin, @@userID, @@aggregation







      &JavascriptReportInit;
      /* <flatten type="Javascript"> */
function init$GridQuery$(g) {
  var a = g._queryFilterString.split(String.fromCharCode(253));
  g._alterTitle = [null, [['%c', a[0], true], ['%s', g._jobName, true], ['%d1', formatDateView(a[1]), true], ['%d2', formatDateView(a[2]), true]]];
  var y = a[16];
  g._hiddenFields = [{Fields: 'ps_no_nt, ps_co_nt', Value: (y == '10')}];
}
/* </flatten> */



